using System;
using System.Runtime.InteropServices;

namespace HP.OCI.Core.Services
{
    /// <summary>
    /// Domain service that incorrectly pulls in native interop.
    /// This violates ARCH_DOMAIN_PINVOKE.
    /// </summary>
    public sealed class OciNativeService
    {
        [DllImport("oci.dll", CharSet = CharSet.Unicode)]
        private static extern int OciGetDeviceStatus(string deviceId);

        public bool IsDeviceReady(string deviceId)
        {
            return OciGetDeviceStatus(deviceId) == 0;
        }
    }
}
